#include <iostream>
#include <vector>
#include <queue>

using namespace std;

int main()
{
    int rows = 3, cols = 3;
    vector<vector<bool>> visited(rows, vector<bool>(cols, false));
    queue<pair<int, int>> q;

    int dr[] = {1, -1, 0, 0};
    int dc[] = {0, 0, 1, -1};

    q.push({0, 0});
    visited[0][0] = true;

    while (!q.empty())
    {
        pair<int, int> current = q.front();
        q.pop();

        cout << current.first << "," << current.second << " ";

        for (int i = 0; i < 4; i++)
        {
            int newRow = current.first + dr[i];
            int newCol = current.second + dc[i];

            if (newRow >= 0 && newRow < rows && newCol >= 0 && newCol < cols && !visited[newRow][newCol])
            {
                visited[newRow][newCol] = true; // mark BEFORE pushing — avoid duplicate queueing
                q.push({newRow, newCol});
            }
        }
    }

    return 0;
}

